import React from "react";
import styleLearningLink from "./Learning_link.module.css";

const Learning_link = () => {
  return (
    <div className={styleLearningLink.about}>
      <h1 className={styleLearningLink.h1}>Learning</h1>
    </div>
  );
};

export default Learning_link;
